// Generates src/theme-palette.json — the sRGB-hex mirror of each theme's
// LIGHT bg-pale, consumed by non-CSS tooling (icons, web manifests).
//
// Single source of truth: the theme LIST + order come from theme.ts; each
// theme's HUE and the bg-pale L/C recipe come from tokens.css. Nothing is
// hardcoded here, so the JSON can't drift from the running UI. `theme-palette`
// is regenerated by `npm run build:palette` (part of `build`); a unit test
// asserts the committed file matches this output.
import { readFile, writeFile } from "node:fs/promises";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const TOKENS = join(ROOT, "src/styles/tokens.css");
const THEME_TS = join(ROOT, "src/theme.ts");
const OUT = join(ROOT, "src/theme-palette.json");

// CSS Color 4 OKLCH -> sRGB hex (deterministic; matches browsers to rounding).
function oklchToHex(L, C, hDeg) {
    const h = (hDeg * Math.PI) / 180;
    const a = C * Math.cos(h);
    const b = C * Math.sin(h);
    const l_ = L + 0.3963377774 * a + 0.2158037573 * b;
    const m_ = L - 0.1055613458 * a - 0.0638541728 * b;
    const s_ = L - 0.0894841775 * a - 1.291485548 * b;
    const l = l_ ** 3;
    const m = m_ ** 3;
    const s = s_ ** 3;
    const lin = [
        4.0767416621 * l - 3.3077115913 * m + 0.2309699292 * s,
        -1.2684380046 * l + 2.6097574011 * m - 0.3413193965 * s,
        -0.0041960863 * l - 0.7034186147 * m + 1.707614701 * s,
    ];
    const hex = lin
        .map((c) => {
            const e =
                c <= 0.0031308 ? 12.92 * c : 1.055 * c ** (1 / 2.4) - 0.055;
            const n = Math.round(Math.max(0, Math.min(1, e)) * 255);
            return n.toString(16).padStart(2, "0");
        })
        .join("");
    return `#${hex}`;
}

export async function generatePalette() {
    const [css, ts] = await Promise.all([
        readFile(TOKENS, "utf8"),
        readFile(THEME_TS, "utf8"),
    ]);

    // Theme list + order: theme.ts is the source of truth for which themes exist.
    const arr = ts.match(/export const themes = \[([\s\S]*?)\] as const;/);
    if (!arr) throw new Error("themes array not found in theme.ts");
    const themes = [...arr[1].matchAll(/"([^"]+)"/g)].map((m) => m[1]);

    // bg-pale recipe L/C (the LIGHT one — first occurrence in the file).
    const recipe = css.match(
        /--polli-color-bg-pale:\s*oklch\(([\d.]+) ([\d.]+) var\(--polli-hue\)\)/,
    );
    if (!recipe)
        throw new Error("light bg-pale recipe not found in tokens.css");
    const paleL = +recipe[1];
    const paleC = +recipe[2];

    // neutral bg-pale === light surface-opaque (first/`:root` occurrence).
    const surf = css.match(
        /--polli-color-surface-opaque:\s*oklch\(([\d.]+) ([\d.]+) ([\d.]+)\)/,
    );
    if (!surf) throw new Error("surface-opaque not found in tokens.css");
    const neutralHex = oklchToHex(+surf[1], +surf[2], +surf[3]);

    const brand = css.match(/--polli-color-brand-dark:\s*(#[0-9a-fA-F]{6})/);
    if (!brand) throw new Error("brand-dark not found in tokens.css");

    const bgPale = {};
    for (const name of themes) {
        if (name === "neutral") {
            bgPale[name] = neutralHex;
            continue;
        }
        const hue = css.match(
            new RegExp(
                `\\[data-theme="${name}"\\]\\s*\\{[^}]*--polli-hue:\\s*([\\-\\d.]+)`,
            ),
        );
        if (!hue) throw new Error(`--polli-hue not found for theme "${name}"`);
        bgPale[name] = oklchToHex(paleL, paleC, +hue[1]);
    }
    return { bgPale, brandDark: brand[1] };
}

// CLI: write the file when invoked directly (not when imported by the test).
if (
    process.argv[1] &&
    resolve(process.argv[1]) === fileURLToPath(import.meta.url)
) {
    generatePalette().then(async (palette) => {
        await writeFile(OUT, `${JSON.stringify(palette, null, 4)}\n`);
        console.log("wrote", OUT);
    });
}
